@page "/settings"
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-dashboard">
    <div class="settings-sidebar">
        <SettingsSidebar ActiveSection="@activeSection" OnSectionChanged="@(s => activeSection = s)" />
    </div>
    <div class="settings-content">
        @switch (activeSection)
        {
            case "Profile":
                <ProfileSection />
                break;
            case "Notifications":
                <NotificationsSection />
                break;
            case "Security":
                <SecuritySection />
                break;
            case "Appearance":
                <AppearanceSection />
                break;
        }
    </div>
</div>

@code {
    private string activeSection = "Profile";
}

.settings-dashboard {
    display: flex;
    min-height: calc(100vh - 3.5rem);
}

.settings-sidebar {
    width: 240px;
    flex-shrink: 0;
    background-color: #f8f9fa;
    border-right: 1px solid #dee2e6;
}

.settings-content {
    flex: 1;
    padding: 2rem;
    max-width: 800px;
}

.settings-nav {
    padding: 1.5rem 0;
}

.settings-nav-title {
    padding: 0 1.25rem;
    margin-bottom: 1rem;
    font-weight: 600;
    color: #6c757d;
    text-transform: uppercase;
    font-size: 0.75rem;
    letter-spacing: 0.05em;
}

.settings-nav-item {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    width: 100%;
    padding: 0.625rem 1.25rem;
    border: none;
    background: none;
    color: #212529;
    font-size: 0.95rem;
    cursor: pointer;
    transition: background-color 0.15s;
    text-align: left;
}

.settings-nav-item:hover {
    background-color: rgba(0, 0, 0, 0.05);
}

.settings-nav-item.active {
    background-color: #0d6efd;
    color: white;
    font-weight: 500;
}

.settings-nav-icon {
    font-size: 1.1rem;
}

