@inject ISettingsService SettingsService

<h3 class="mb-4">Profile Settings</h3>

@if (loading)
{
    <div class="text-center py-5">
        <div class="spinner-border" role="status"><span class="visually-hidden">Loading…</span></div>
    </div>
}
else if (profile is not null)
{
    @if (statusMessage is not null)
    {
        <div class="alert @(isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
            @statusMessage
            <button type="button" class="btn-close" @onclick="@(() => statusMessage = null)"></button>
        </div>
    }

    <div class="card mb-4">
        <div class="card-body">
            <div class="d-flex align-items-center mb-4">
                <div class="me-3">
                    @if (!string.IsNullOrEmpty(editProfile.AvatarUrl))
                    {
                        <img src="@editProfile.AvatarUrl" alt="Avatar" class="rounded-circle" width="80" height="80" />
                    }
                    else
                    {
                        <div class="rounded-circle d-flex align-items-center justify-content-center bg-light"
                             style="width:80px;height:80px;font-size:2rem;">👤</div>
                    }
                </div>
                <div class="flex-grow-1">
                    <label class="form-label fw-semibold">Avatar URL</label>
                    <input type="url" class="form-control" @bind="editProfile.AvatarUrl"
                           placeholder="https://example.com/avatar.png" />
                </div>
            </div>

            <div class="mb-3">
                <label class="form-label fw-semibold">Display Name</label>
                <input type="text" class="form-control" @bind="editProfile.DisplayName" />
            </div>

            <div class="mb-3">
                <label class="form-label fw-semibold">Email</label>
                <input type="email" class="form-control" @bind="editProfile.Email" />
            </div>

            <div class="mb-3">
                <label class="form-label fw-semibold">Bio</label>
                <textarea class="form-control" rows="4" @bind="editProfile.Bio"></textarea>
            </div>

            <div class="d-flex gap-2">
                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@saving">
                    @if (saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Save Changes
                </button>
                <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@saving">
                    Discard Changes
                </button>
            </div>
        </div>
    </div>
}

@code {
    private bool loading = true;
    private bool saving;
    private string? statusMessage;
    private bool isError;
    private UserProfile? profile;
    private readonly EditableProfile editProfile = new();

    private sealed class EditableProfile
    {
        public string DisplayName { get; set; } = "";
        public string Email { get; set; } = "";
        public string AvatarUrl { get; set; } = "";
        public string Bio { get; set; } = "";
    }

    protected override async Task OnInitializedAsync()
    {
        profile = await SettingsService.GetProfileAsync();
        CopyToEdit(profile);
        loading = false;
    }

    private void CopyToEdit(UserProfile p)
    {
        editProfile.DisplayName = p.DisplayName;
        editProfile.Email = p.Email;
        editProfile.AvatarUrl = p.AvatarUrl;
        editProfile.Bio = p.Bio;
    }

    private async Task SaveAsync()
    {
        saving = true;
        statusMessage = null;
        try
        {
            var updated = new UserProfile(
                editProfile.DisplayName, editProfile.Email,
                editProfile.AvatarUrl, editProfile.Bio);
            await SettingsService.SaveProfileAsync(updated);
            profile = updated;
            statusMessage = "Profile saved successfully!";
            isError = false;
        }
        catch (Exception ex)
        {
            statusMessage = $"Failed to save: {ex.Message}";
            isError = true;
        }
        finally
        {
            saving = false;
        }
    }

    private void Discard()
    {
        if (profile is not null)
        {
            CopyToEdit(profile);
            statusMessage = null;
        }
    }
}

@inject ISettingsService SettingsService

<h3 class="mb-4">Notification Preferences</h3>

@if (loading)
{
    <div class="text-center py-5">
        <div class="spinner-border" role="status"><span class="visually-hidden">Loading…</span></div>
    </div>
}
else if (prefs is not null)
{
    @if (statusMessage is not null)
    {
        <div class="alert @(isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
            @statusMessage
            <button type="button" class="btn-close" @onclick="@(() => statusMessage = null)"></button>
        </div>
    }

    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title mb-3">General</h5>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch"
                       id="emailNotif" @bind="emailNotifications" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch"
                       id="pushNotif" @bind="pushNotifications" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch"
                       id="weeklyDigest" @bind="weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title mb-3">Muted Channels</h5>
            @if (allChannels.Length == 0)
            {
                <p class="text-muted">No channels available.</p>
            }
            else
            {
                @foreach (var channel in allChannels)
                {
                    <div class="form-check mb-2">
                        <input class="form-check-input" type="checkbox"
                               id="@($"ch-{channel}")"
                               checked="@mutedChannels.Contains(channel)"
                               @onchange="@(e => ToggleChannel(channel, (bool)(e.Value ?? false)))" />
                        <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                    </div>
                }
            }
        </div>
    </div>

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@saving">
        @if (saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
        Save Preferences
    </button>
}

@code {
    private bool loading = true;
    private bool saving;
    private string? statusMessage;
    private bool isError;
    private NotificationPrefs? prefs;

    private bool emailNotifications;
    private bool pushNotifications;
    private bool weeklyDigest;
    private HashSet<string> mutedChannels = new();

    private static readonly string[] allChannels =
        ["general", "announcements", "engineering", "design", "marketing", "random"];

    protected override async Task OnInitializedAsync()
    {
        prefs = await SettingsService.GetNotificationPrefsAsync();
        emailNotifications = prefs.EmailNotifications;
        pushNotifications = prefs.PushNotifications;
        weeklyDigest = prefs.WeeklyDigest;
        mutedChannels = new HashSet<string>(prefs.MutedChannels);
        loading = false;
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted) mutedChannels.Add(channel);
        else mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        saving = true;
        statusMessage = null;
        try
        {
            var updated = new NotificationPrefs(
                emailNotifications, pushNotifications,
                weeklyDigest, mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(updated);
            prefs = updated;
            statusMessage = "Preferences saved successfully!";
            isError = false;
        }
        catch (Exception ex)
        {
            statusMessage = $"Failed to save: {ex.Message}";
            isError = true;
        }
        finally
        {
            saving = false;
        }
    }
}

@inject ISettingsService SettingsService

<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center"
         role="button" @onclick="ToggleExpanded">
        <h5 class="mb-0">Change Password</h5>
        <span>@(expanded ? "▲" : "▼")</span>
    </div>
    @if (expanded)
    {
        <div class="card-body">
            @if (statusMessage is not null)
            {
                <div class="alert @(isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                    @statusMessage
                    <button type="button" class="btn-close" @onclick="@(() => statusMessage = null)"></button>
                </div>
            }

            <div class="mb-3">
                <label class="form-label fw-semibold">Current Password</label>
                <input type="password" class="form-control" @bind="currentPassword" />
            </div>

            <div class="mb-3">
                <label class="form-label fw-semibold">New Password</label>
                <input type="password" class="form-control" @bind="newPassword" />
            </div>

            <div class="mb-3">
                <label class="form-label fw-semibold">Confirm New Password</label>
                <input type="password" class="form-control" @bind="confirmPassword" />
            </div>

            <button class="btn btn-primary" @onclick="UpdatePasswordAsync" disabled="@saving">
                @if (saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback OnPasswordChanged { get; set; }

    private bool expanded;
    private bool saving;
    private string? statusMessage;
    private bool isError;
    private string currentPassword = "";
    private string newPassword = "";
    private string confirmPassword = "";

    private void ToggleExpanded() => expanded = !expanded;

    private async Task UpdatePasswordAsync()
    {
        statusMessage = null;

        if (string.IsNullOrWhiteSpace(currentPassword) || string.IsNullOrWhiteSpace(newPassword))
        {
            statusMessage = "Please fill in all password fields.";
            isError = true;
            return;
        }

        if (newPassword != confirmPassword)
        {
            statusMessage = "New password and confirmation do not match.";
            isError = true;
            return;
        }

        saving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(currentPassword, newPassword);
            statusMessage = "Password updated successfully!";
            isError = false;
            currentPassword = "";
            newPassword = "";
            confirmPassword = "";
            await OnPasswordChanged.InvokeAsync();
        }
        catch (Exception ex)
        {
            statusMessage = $"Failed to update password: {ex.Message}";
            isError = true;
        }
        finally
        {
            saving = false;
        }
    }
}

@inject ISettingsService SettingsService

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title mb-3">Active Sessions</h5>

        @if (statusMessage is not null)
        {
            <div class="alert @(isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @statusMessage
                <button type="button" class="btn-close" @onclick="@(() => statusMessage = null)"></button>
            </div>
        }

        @if (confirmingSessionId is not null)
        {
            <div class="alert alert-warning d-flex align-items-center justify-content-between">
                <span>Are you sure you want to revoke this session?</span>
                <div class="d-flex gap-2">
                    <button class="btn btn-danger btn-sm" @onclick="ConfirmRevoke" disabled="@revoking">
                        @if (revoking) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Revoke
                    </button>
                    <button class="btn btn-outline-secondary btn-sm" @onclick="CancelRevoke" disabled="@revoking">
                        Cancel
                    </button>
                </div>
            </div>
        }

        <div class="table-responsive">
            <table class="table table-hover mb-0">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @for (var i = 0; i < Sessions.Count; i++)
                    {
                        var session = Sessions[i];
                        var isCurrent = i == 0;
                        <tr>
                            <td>
                                @session.Device
                                @if (isCurrent)
                                {
                                    <span class="badge bg-info ms-1">Current</span>
                                }
                            </td>
                            <td>@session.Location</td>
                            <td>@session.LastActive.ToString("g")</td>
                            <td>
                                @if (!isCurrent)
                                {
                                    <button class="btn btn-outline-danger btn-sm"
                                            @onclick="@(() => RequestRevoke(session.Id))"
                                            disabled="@(confirmingSessionId is not null)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    </div>
</div>

@code {
    [Parameter] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public EventCallback OnSessionRevoked { get; set; }

    private string? confirmingSessionId;
    private bool revoking;
    private string? statusMessage;
    private bool isError;

    private void RequestRevoke(string sessionId) => confirmingSessionId = sessionId;
    private void CancelRevoke() => confirmingSessionId = null;

    private async Task ConfirmRevoke()
    {
        if (confirmingSessionId is null) return;

        revoking = true;
        statusMessage = null;
        try
        {
            await SettingsService.RevokeSessionAsync(confirmingSessionId);
            statusMessage = "Session revoked successfully.";
            isError = false;
            confirmingSessionId = null;
            await OnSessionRevoked.InvokeAsync();
        }
        catch (Exception ex)
        {
            statusMessage = $"Failed to revoke session: {ex.Message}";
            isError = true;
        }
        finally
        {
            revoking = false;
        }
    }
}

@inject ISettingsService SettingsService

<h3 class="mb-4">Security Settings</h3>

@if (loading)
{
    <div class="text-center py-5">
        <div class="spinner-border" role="status"><span class="visually-hidden">Loading…</span></div>
    </div>
}
else if (settings is not null)
{
    <ChangePasswordPanel OnPasswordChanged="ReloadAsync" />

    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title mb-3">Two-Factor Authentication</h5>
            <div class="d-flex align-items-center gap-3">
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" role="switch"
                           id="twoFactor" checked="@settings.TwoFactorEnabled" disabled />
                    <label class="form-check-label" for="twoFactor">
                        @(settings.TwoFactorEnabled ? "Enabled" : "Disabled")
                    </label>
                </div>
                <span class="badge @(settings.TwoFactorEnabled ? "bg-success" : "bg-warning text-dark")">
                    @(settings.TwoFactorEnabled ? "✓ Active" : "⚠ Inactive")
                </span>
            </div>
            @if (settings.LastPasswordChange.HasValue)
            {
                <p class="text-muted mt-2 mb-0">
                    Last password change: @settings.LastPasswordChange.Value.ToString("MMMM d, yyyy")
                </p>
            }
        </div>
    </div>

    <ActiveSessionsTable Sessions="@settings.Sessions" OnSessionRevoked="ReloadAsync" />
}

@code {
    private bool loading = true;
    private SecuritySettings? settings;

    protected override async Task OnInitializedAsync()
    {
        settings = await SettingsService.GetSecuritySettingsAsync();
        loading = false;
    }

    private async Task ReloadAsync()
    {
        settings = await SettingsService.GetSecuritySettingsAsync();
    }
}

@inject ISettingsService SettingsService

<h3 class="mb-4">Appearance</h3>

@if (loading)
{
    <div class="text-center py-5">
        <div class="spinner-border" role="status"><span class="visually-hidden">Loading…</span></div>
    </div>
}
else
{
    @if (statusMessage is not null)
    {
        <div class="alert @(isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
            @statusMessage
            <button type="button" class="btn-close" @onclick="@(() => statusMessage = null)"></button>
        </div>
    }

    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title mb-3">Theme</h5>
            @foreach (var theme in themes)
            {
                <div class="form-check mb-2">
                    <input class="form-check-input" type="radio" name="theme"
                           id="@($"theme-{theme}")"
                           checked="@(selectedTheme == theme)"
                           @onchange="@(() => selectedTheme = theme)" />
                    <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                </div>
            }
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title mb-3">Font Size</h5>
            @foreach (var size in fontSizes)
            {
                <div class="form-check form-check-inline">
                    <input class="form-check-input" type="radio" name="fontSize"
                           id="@($"fs-{size}")"
                           checked="@(selectedFontSize == size)"
                           @onchange="@(() => selectedFontSize = size)" />
                    <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                </div>
            }
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title mb-3">Language</h5>
            <select class="form-select" style="max-width:300px;" @bind="selectedLanguage">
                @foreach (var lang in languages)
                {
                    <option value="@lang">@lang</option>
                }
            </select>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title mb-3">Compact Mode</h5>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch"
                       id="compactMode" @bind="compactMode" />
                <label class="form-check-label" for="compactMode">Enable compact mode</label>
            </div>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title mb-3">Preview</h5>
            <div class="appearance-preview @PreviewThemeClass" style="@PreviewStyle">
                <div class="preview-header">
                    <strong>Sample Dashboard</strong>
                </div>
                <div class="preview-body">
                    <p class="mb-2">This is how your content will look with the selected settings.</p>
                    <button class="btn btn-sm @PreviewButtonClass">Sample Button</button>
