        {
            var updated = new NotificationPrefs(
                emailNotifications, pushNotifications,
                weeklyDigest, mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(updated);
            prefs = updated;
            statusMessage = "Preferences saved successfully!";
            isError = false;
