@code {
    [Parameter] public EventCallback OnPasswordChanged { get; set; }

    private bool expanded;
    private bool saving;
    private string? statusMessage;
    private bool isError;
    private string currentPassword = "";
    private string newPassword = "";
    private string confirmPassword = "";

    private void ToggleExpanded() => expanded = !expanded;

    private async Task UpdatePasswordAsync()
    {
        statusMessage = null;

        if (string.IsNullOrWhiteSpace(currentPassword) || string.IsNullOrWhiteSpace(newPassword))
        {
            statusMessage = "Please fill in all password fields.";
            isError = true;
            return;
        }

        if (newPassword != confirmPassword)
        {
            statusMessage = "New password and confirmation do not match.";
            isError = true;
            return;
        }

        saving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(currentPassword, newPassword);
            statusMessage = "Password updated successfully!";
            isError = false;
            currentPassword = "";
            newPassword = "";
            confirmPassword = "";
            await OnPasswordChanged.InvokeAsync();
        }
        catch (Exception ex)
        {
            statusMessage = $"Failed to update password: {ex.Message}";
            isError = true;
        }
        finally
        {
            saving = false;
        }
    }
}

