                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@saving">
                    @if (saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                    Save Changes
                </button>
                <button class="btn btn-outline-secondary" @onclick="Discard" disabled="@saving">
                    Discard Changes
                </button>
            </div>
        </div>
    </div>
}

@code {
    private bool loading = true;
    private bool saving;
    private string? statusMessage;
    private bool isError;
    private UserProfile? profile;
    private readonly EditableProfile editProfile = new();

    private sealed class EditableProfile
    {
        public string DisplayName { get; set; } = "";
        public string Email { get; set; } = "";
        public string AvatarUrl { get; set; } = "";
        public string Bio { get; set; } = "";
    }

    protected override async Task OnInitializedAsync()
    {
        profile = await SettingsService.GetProfileAsync();
        CopyToEdit(profile);
        loading = false;
    }

    private void CopyToEdit(UserProfile p)
    {
        editProfile.DisplayName = p.DisplayName;
        editProfile.Email = p.Email;
        editProfile.AvatarUrl = p.AvatarUrl;
        editProfile.Bio = p.Bio;
    }

    private async Task SaveAsync()
    {
        saving = true;
        statusMessage = null;
        try
        {
            var updated = new UserProfile(
                editProfile.DisplayName, editProfile.Email,
                editProfile.AvatarUrl, editProfile.Bio);
            await SettingsService.SaveProfileAsync(updated);
            profile = updated;
            statusMessage = "Profile saved successfully!";
            isError = false;
        }
        catch (Exception ex)
        {
            statusMessage = $"Failed to save: {ex.Message}";
            isError = true;
        }
        finally
        {
            saving = false;
        }
    }

    private void Discard()
    {
        if (profile is not null)
        {
            CopyToEdit(profile);
            statusMessage = null;
        }
    }
}
