<div class="card mb-4">
    <div class="card-header d-flex justify-content-between align-items-center"
         role="button" @onclick="ToggleExpanded">
        <h5 class="mb-0">Change Password</h5>
        <span>@(expanded ? "▲" : "▼")</span>
    </div>
    @if (expanded)
    {
        <div class="card-body">
            @if (statusMessage is not null)
            {
                <div class="alert @(isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                    @statusMessage
                    <button type="button" class="btn-close" @onclick="@(() => statusMessage = null)"></button>
                </div>
            }

            <div class="mb-3">
                <label class="form-label fw-semibold">Current Password</label>
                <input type="password" class="form-control" @bind="currentPassword" />
            </div>

            <div class="mb-3">
                <label class="form-label fw-semibold">New Password</label>
                <input type="password" class="form-control" @bind="newPassword" />
            </div>

            <div class="mb-3">
                <label class="form-label fw-semibold">Confirm New Password</label>
                <input type="password" class="form-control" @bind="confirmPassword" />
            </div>

            <button class="btn btn-primary" @onclick="UpdatePasswordAsync" disabled="@saving">
                @if (saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Update Password
            </button>
        </div>
    }
</div>

@code {
    [Parameter] public EventCallback OnPasswordChanged { get; set; }

    private bool expanded;
    private bool saving;
    private string? statusMessage;
    private bool isError;
    private string currentPassword = "";
    private string newPassword = "";
    private string confirmPassword = "";

    private void ToggleExpanded() => expanded = !expanded;

    private async Task UpdatePasswordAsync()
    {
        statusMessage = null;

        if (string.IsNullOrWhiteSpace(currentPassword) || string.IsNullOrWhiteSpace(newPassword))
        {
            statusMessage = "Please fill in all password fields.";
            isError = true;
            return;
        }

        if (newPassword != confirmPassword)
        {
            statusMessage = "New password and confirmation do not match.";
            isError = true;
            return;
        }

        saving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(currentPassword, newPassword);
            statusMessage = "Password updated successfully!";
            isError = false;
            currentPassword = "";
            newPassword = "";
            confirmPassword = "";
            await OnPasswordChanged.InvokeAsync();
        }
        catch (Exception ex)
        {
            statusMessage = $"Failed to update password: {ex.Message}";
            isError = true;
        }
        finally
        {
            saving = false;
        }
    }
}
