<h3 class="mb-4">Appearance</h3>

@if (loading)
{
    <div class="text-center py-5">
        <div class="spinner-border" role="status"><span class="visually-hidden">Loading…</span></div>
    </div>
}
else
{
    @if (statusMessage is not null)
    {
        <div class="alert @(isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
            @statusMessage
            <button type="button" class="btn-close" @onclick="@(() => statusMessage = null)"></button>
        </div>
    }

    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title mb-3">Theme</h5>
            @foreach (var theme in themes)
            {
                <div class="form-check mb-2">
                    <input class="form-check-input" type="radio" name="theme"
                           id="@($"theme-{theme}")"
                           checked="@(selectedTheme == theme)"
                           @onchange="@(() => selectedTheme = theme)" />
                    <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                </div>
            }
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title mb-3">Font Size</h5>
            @foreach (var size in fontSizes)
            {
                <div class="form-check form-check-inline">
                    <input class="form-check-input" type="radio" name="fontSize"
                           id="@($"fs-{size}")"
                           checked="@(selectedFontSize == size)"
                           @onchange="@(() => selectedFontSize = size)" />
                    <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                </div>
            }
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title mb-3">Language</h5>
            <select class="form-select" style="max-width:300px;" @bind="selectedLanguage">
                @foreach (var lang in languages)
                {
                    <option value="@lang">@lang</option>
                }
            </select>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title mb-3">Compact Mode</h5>
            <div class="form-check form-switch">
                <input class="form-check-input" type="checkbox" role="switch"
                       id="compactMode" @bind="compactMode" />
                <label class="form-check-label" for="compactMode">Enable compact mode</label>
            </div>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title mb-3">Preview</h5>
            <div class="appearance-preview @PreviewThemeClass" style="@PreviewStyle">
                <div class="preview-header">
                    <strong>Sample Dashboard</strong>
                </div>
                <div class="preview-body">
                    <p class="mb-2">This is how your content will look with the selected settings.</p>
                    <button class="btn btn-sm @PreviewButtonClass">Sample Button</button>
                    <span class="ms-2 badge @PreviewBadgeClass">Status Badge</span>
                </div>
            </div>
        </div>
    </div>

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@saving">
        @if (saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
        Save
    </button>
}

@code {
    private bool loading = true;
    private bool saving;
    private string? statusMessage;
    private bool isError;

    private string selectedTheme = "Light";
    private string selectedFontSize = "Medium";
    private string selectedLanguage = "English";
    private bool compactMode;

    private static readonly string[] themes = ["Light", "Dark", "System"];
    private static readonly string[] fontSizes = ["Small", "Medium", "Large"];
    private static readonly string[] languages =
        ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    private string PreviewThemeClass => selectedTheme switch
    {
        "Dark" => "preview-dark",
        _ => "preview-light",
    };

    private string PreviewButtonClass => selectedTheme == "Dark" ? "btn-light" : "btn-primary";
    private string PreviewBadgeClass => selectedTheme == "Dark" ? "bg-light text-dark" : "bg-primary";

    private string PreviewStyle
    {
        get
        {
            var fs = selectedFontSize switch
            {
                "Small" => "0.85rem",
                "Large" => "1.15rem",
                _ => "1rem",
            };
            var pad = compactMode ? "0.5rem" : "1rem";
            return $"font-size:{fs};--preview-padding:{pad};";
        }
    }

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        selectedTheme = settings.Theme;
        selectedFontSize = settings.FontSize;
        selectedLanguage = settings.Language;
        compactMode = settings.CompactMode;
        loading = false;
    }

    private async Task SaveAsync()
    {
        saving = true;
        statusMessage = null;
        try
        {
            var updated = new AppearanceSettings(
                selectedTheme, selectedFontSize, selectedLanguage, compactMode);
            await SettingsService.SaveAppearanceAsync(updated);
            statusMessage = "Appearance settings saved!";
            isError = false;
        }
        catch (Exception ex)
        {
            statusMessage = $"Failed to save: {ex.Message}";
            isError = true;
        }
        finally
        {
            saving = false;
        }
    }
}
