@inject ISettingsService SettingsService

<h3 class="mb-4">Notification Preferences</h3>

@if (loading)
{
    <div class="text-center py-5">
        <div class="spinner-border" role="status"><span class="visually-hidden">Loading…</span></div>
    </div>
}
else if (prefs is not null)
{
    @if (statusMessage is not null)
    {
        <div class="alert @(isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
            @statusMessage
            <button type="button" class="btn-close" @onclick="@(() => statusMessage = null)"></button>
        </div>
    }

    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title mb-3">General</h5>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch"
                       id="emailNotif" @bind="emailNotifications" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch"
                       id="pushNotif" @bind="pushNotifications" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" role="switch"
                       id="weeklyDigest" @bind="weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>
        </div>
    </div>

    <div class="card mb-4">
        <div class="card-body">
            <h5 class="card-title mb-3">Muted Channels</h5>
            @if (allChannels.Length == 0)
            {
                <p class="text-muted">No channels available.</p>
            }
            else
            {
                @foreach (var channel in allChannels)
                {
                    <div class="form-check mb-2">
                        <input class="form-check-input" type="checkbox"
                               id="@($"ch-{channel}")"
                               checked="@mutedChannels.Contains(channel)"
                               @onchange="@(e => ToggleChannel(channel, (bool)(e.Value ?? false)))" />
                        <label class="form-check-label" for="@($"ch-{channel}")">@channel</label>
                    </div>
                }
            }
        </div>
    </div>

    <button class="btn btn-primary" @onclick="SaveAsync" disabled="@saving">
        @if (saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
        Save Preferences
    </button>
}

@code {
    private bool loading = true;
    private bool saving;
    private string? statusMessage;
    private bool isError;
    private NotificationPrefs? prefs;

    private bool emailNotifications;
    private bool pushNotifications;
    private bool weeklyDigest;
    private HashSet<string> mutedChannels = new();

    private static readonly string[] allChannels =
        ["general", "announcements", "engineering", "design", "marketing", "random"];

    protected override async Task OnInitializedAsync()
    {
        prefs = await SettingsService.GetNotificationPrefsAsync();
        emailNotifications = prefs.EmailNotifications;
        pushNotifications = prefs.PushNotifications;
        weeklyDigest = prefs.WeeklyDigest;
        mutedChannels = new HashSet<string>(prefs.MutedChannels);
        loading = false;
    }

    private void ToggleChannel(string channel, bool muted)
    {
        if (muted) mutedChannels.Add(channel);
        else mutedChannels.Remove(channel);
    }

    private async Task SaveAsync()
    {
        saving = true;
        statusMessage = null;
        try
        {
            var updated = new NotificationPrefs(
                emailNotifications, pushNotifications,
                weeklyDigest, mutedChannels.ToList());
            await SettingsService.SaveNotificationPrefsAsync(updated);
            prefs = updated;
            statusMessage = "Preferences saved successfully!";
            isError = false;
        }
        catch (Exception ex)
        {
            statusMessage = $"Failed to save: {ex.Message}";
            isError = true;
        }
        finally
        {
            saving = false;
        }
    }
}

