@inject ISettingsService SettingsService

<div class="card mb-4">
    <div class="card-body">
        <h5 class="card-title mb-3">Active Sessions</h5>

        @if (statusMessage is not null)
        {
            <div class="alert @(isError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @statusMessage
                <button type="button" class="btn-close" @onclick="@(() => statusMessage = null)"></button>
            </div>
        }

        @if (confirmingSessionId is not null)
        {
            <div class="alert alert-warning d-flex align-items-center justify-content-between">
                <span>Are you sure you want to revoke this session?</span>
                <div class="d-flex gap-2">
                    <button class="btn btn-danger btn-sm" @onclick="ConfirmRevoke" disabled="@revoking">
                        @if (revoking) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Revoke
                    </button>
                    <button class="btn btn-outline-secondary btn-sm" @onclick="CancelRevoke" disabled="@revoking">
                        Cancel
                    </button>
                </div>
            </div>
        }

        <div class="table-responsive">
            <table class="table table-hover mb-0">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @for (var i = 0; i < Sessions.Count; i++)
                    {
                        var session = Sessions[i];
                        var isCurrent = i == 0;
                        <tr>
                            <td>
                                @session.Device
                                @if (isCurrent)
                                {
                                    <span class="badge bg-info ms-1">Current</span>
                                }
                            </td>
                            <td>@session.Location</td>
                            <td>@session.LastActive.ToString("g")</td>
                            <td>
                                @if (!isCurrent)
                                {
                                    <button class="btn btn-outline-danger btn-sm"
                                            @onclick="@(() => RequestRevoke(session.Id))"
                                            disabled="@(confirmingSessionId is not null)">
                                        Revoke
                                    </button>
                                }
                            </td>
                        </tr>
                    }
                </tbody>
            </table>
        </div>
    </div>
</div>

@code {
    [Parameter] public List<ActiveSession> Sessions { get; set; } = [];
    [Parameter] public EventCallback OnSessionRevoked { get; set; }

    private string? confirmingSessionId;
    private bool revoking;
    private string? statusMessage;
    private bool isError;

    private void RequestRevoke(string sessionId) => confirmingSessionId = sessionId;
    private void CancelRevoke() => confirmingSessionId = null;

    private async Task ConfirmRevoke()
    {
        if (confirmingSessionId is null) return;

        revoking = true;
        statusMessage = null;
        try
        {
            await SettingsService.RevokeSessionAsync(confirmingSessionId);
            statusMessage = "Session revoked successfully.";
            isError = false;
            confirmingSessionId = null;
            await OnSessionRevoked.InvokeAsync();
        }
        catch (Exception ex)
        {
            statusMessage = $"Failed to revoke session: {ex.Message}";
            isError = true;
        }
        finally
        {
            revoking = false;
        }
    }
}

